import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, LayoutGrid } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminSections = () => {
  const [sections, setSections] = useState<any[]>([]);

  const fetchSections = async () => {
    try {
      const res: any = await AdminService.getAllSections();
      setSections(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      toast.error("Sections Sync Failed");
      setSections([]);
    }
  };

  useEffect(() => { fetchSections(); }, []);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase tracking-tighter italic">Archive <span className="text-primary">Sections</span></h1>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Structural Segments</p>
        </div>
        <Link to="/admin/sections/add" className="bg-black text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-primary transition-all">
          <Plus size={16} /> New Section
        </Link>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {sections.map((sec: any) => (
          <div key={sec._id} className="bg-white dark:bg-[#0f0f0f] p-8 rounded-[2.5rem] border border-gray-100 dark:border-white/5 flex items-center justify-between group shadow-sm">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-primary/10 rounded-xl">
                <LayoutGrid className="text-primary" size={20} />
              </div>
              <div>
                <h4 className="font-black uppercase text-xs italic">{sec.Section_ID}</h4>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{sec.Title_En}</p>
              </div>
            </div>
            <div className="flex gap-2">
              <Link to={`/admin/sections/edit/${sec.Section_ID}`} className="p-3 bg-gray-50 dark:bg-white/5 rounded-xl text-[9px] font-black uppercase hover:bg-black hover:text-white transition-all">Modify</Link>
              <button className="p-3 bg-red-50 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all"><Trash2 size={16}/></button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};
